import { readFile } from "node:fs/promises";
import { createRequire } from "node:module";
import { createEmbeddedFontWasmDecoder, } from "./wasm-decoder.js";
export * from "./types.js";
export { createEmbeddedFontWasmDecoder, decodeEmbeddedFontWithWasm, } from "./wasm-decoder.js";
export const EMBEDDED_FONT_DECODER_WASM_EXPORT = "@officer/embedded-fonts/embedded_font_decoder.wasm";
/**
 * Resolves the WASM shipped by the installed package version and creates a
 * decoder. Runtime hosts own lazy/process-wide caching of the returned decoder.
 */
export async function loadEmbeddedFontDecoder() {
    const require = createRequire(import.meta.url);
    const wasmPath = require.resolve(EMBEDDED_FONT_DECODER_WASM_EXPORT);
    const bytes = await readFile(wasmPath);
    const source = bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength);
    return createEmbeddedFontWasmDecoder(source);
}
